import React from "react";
import KitsContainer from "../../helpers/FormContainer";
import { CascadeSelect } from "primereact/cascadeselect";
import type { ICascadeSelect } from "@lmb-it/kitsconcerto-types";
import { useKitsTheme } from "../../../contexts/Theme";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useSelectBase } from "../hooks/useSelectBase";

const KitsCascadeSelect = ({ className, ref, ...rawProps }: ICascadeSelect) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('CascadeSelect', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        rightAddon,
        leftAddon,
        errors,
        invalid,
        required,
        label,
        isFloatedLabel,
        id,
        localProps,
        disabled,
        inputSize,
        placeholder,
        helperText,
        attached,
        hideError,
        loading,
        withFilter,
        containerStyle,
    } = props;

    const { list, keys, onChange, selectedValue } = useSelectBase();

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const Element = (
        <CascadeSelect
            value={selectedValue}
            options={Array.isArray(list) ? list : []}
            optionLabel={keys.optionLabel}
            optionGroupLabel={keys.optionGroupLabel}
            optionGroupChildren={keys.optionGroupChildren ? [keys.optionGroupChildren] : undefined}
            disabled={disabled}
            loading={loading}
            placeholder={placeholder}
            onChange={(e) => onChange({ target: { value: e.value } }, e.value)}
            className="w-full"
            style={{ minWidth: "14rem", borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
            pt={{
                root: {
                    style: {
                        borderColor: borderColor,
                    }
                },
                item: ({ context }: any) => context?.selected ? {
                    style: { backgroundColor: primaryColor, color: 'white' }
                } : context?.focused ? {
                    style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
                } : undefined,
            }}
            {...(localProps ? localProps : {})}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};
export default KitsCascadeSelect;
